import{_ as e,o as n,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const v=JSON.parse('{"title":"Snap Advanced Conversions","description":"","frontmatter":{"title":"Snap Advanced Conversions","slug":"snap-advanced-conversions"},"headers":[],"relativePath":"marketer-hub/snap-advanced-conversions.md","filePath":"marketer-hub/snap-advanced-conversions.md"}'),t={name:"marketer-hub/snap-advanced-conversions.md"};function s(i,a,d,h,p,c){return n(),o("div",null,[...a[0]||(a[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Advanced Conversions is Snap’s privacy-centric approach to digital advertising. It helps marketers meet their business objectives while respecting users’ ad tracking preferences via Apple’s ATT policy. This methodology employs a range of cryptographic techniques to measure aggregate conversion data, without tying off-platform activities (like installing an app or visiting a website) back to specific Snapchatters.</p><p>Advanced Conversions reporting is compatible for web and offline events via the Snap Pixel and Conversions API through integration with Branch through a Dashboard toggle.</p><p><strong>Note:</strong> Snap Advanced Conversions is <strong>DISABLED</strong> by default; thus, Branch will only send iOS user data to Snap for those who have opted-in to ATT. Follow our guide on <a href="./snap-advanced-conversions.html#enabling-snap-advanced-conversions">Enabling Snap Advanced Conversions</a> to turn on.</p><h2 id="enable-snap-advanced-conversions" tabindex="-1">Enable Snap Advanced Conversions <a class="header-anchor" href="#enable-snap-advanced-conversions" aria-label="Permalink to &quot;Enable Snap Advanced Conversions&quot;">​</a></h2><h4 id="_1-navigate-to-snap-in-branch" tabindex="-1">1. Navigate to Snap in Branch <a class="header-anchor" href="#_1-navigate-to-snap-in-branch" aria-label="Permalink to &quot;1. Navigate to Snap in Branch&quot;">​</a></h4><p>In the Branch Dashboard under <strong>Ads &gt; Partner Management</strong>, find/search for <strong>Snap</strong>. If you&#39;re already logged into the Branch Dashboard, you can also click <a href="https://dashboard.branch.io/ads/partner-management/a_snap?tab=settings" target="_blank" rel="noreferrer">here</a> to go there directly.</p><h4 id="_2-enable-snap-advanced-conversions" tabindex="-1">2. Enable Snap Advanced Conversions <a class="header-anchor" href="#_2-enable-snap-advanced-conversions" aria-label="Permalink to &quot;2. Enable Snap Advanced Conversions&quot;">​</a></h4><p>Under the <a href="https://dashboard.branch.io/ads/partner-management/a_snap?tab=event_config" target="_blank" rel="noreferrer"><strong>Events Config</strong></a> tab, toggle on the <strong>Enable Snap Advance Conversions</strong> checkbox. Click the <strong>Save</strong> button.</p><h2 id="pass-hashed-data" tabindex="-1">Pass hashed Data <a class="header-anchor" href="#pass-hashed-data" aria-label="Permalink to &quot;Pass hashed Data&quot;">​</a></h2><p>This step is <strong>optional</strong> and requires help from your development team.</p><p>In order to better help optimize ads and build improved re-marketing audiences, you can optionally send hashed PII (i.e. phone numbers or email addresses) to model conversion events for Snap Advanced Matching.</p><p>To learn more, visit our <a href="https://help.branch.io/developer-hub/docs/pass-hashed-data-to-snap" target="_blank" rel="noreferrer">guide</a> in Developer Hub.</p><h2 id="see-the-data-in-snap" tabindex="-1">See the data in Snap <a class="header-anchor" href="#see-the-data-in-snap" aria-label="Permalink to &quot;See the data in Snap&quot;">​</a></h2><p>Due to privacy constraints, the data will appear in Snap&#39;s dashboard <strong>after</strong> the conversion volume crosses a threshold on Snap&#39;s side. After turning this on, your Snap support team can help advise on when to expect the data to appear in their dashboard.</p>',15)])])}const g=e(t,[["render",s]]);export{v as __pageData,g as default};
